def gen(rng, size):
    n = max(1, min(size, 100000))
    nums = []
    val = rng.randint(1, 1000)
    for _ in range(n):
        if rng.random() < 0.05:
            val = rng.randint(1, 1000)
        nums.append(val)
    k = rng.randint(0, 100)
    return [nums, k]

