class Solution:
    def countSubarrays(self, nums, k):
        # Direct O(n^2) definition-based check: for every left endpoint, extend
        # the right endpoint one step at a time, tracking max/min directly
        # (no deques, no two-pointer) -- independent of the optimal approach.
        n = len(nums)
        total = 0
        for l in range(n):
            cur_max = nums[l]
            cur_min = nums[l]
            for r in range(l, n):
                if nums[r] > cur_max:
                    cur_max = nums[r]
                if nums[r] < cur_min:
                    cur_min = nums[r]
                length = r - l + 1
                if (cur_max - cur_min) * length <= k:
                    total += 1
        return total

