from collections import deque

class Solution:
    def countSubarrays(self, nums, k):
        n = len(nums)
        max_dq = deque()  # indices, values strictly decreasing front-to-back
        min_dq = deque()  # indices, values strictly increasing front-to-back
        l = 0
        total = 0
        for r in range(n):
            while max_dq and nums[max_dq[-1]] <= nums[r]:
                max_dq.pop()
            max_dq.append(r)
            while min_dq and nums[min_dq[-1]] >= nums[r]:
                min_dq.pop()
            min_dq.append(r)
            while (nums[max_dq[0]] - nums[min_dq[0]]) * (r - l + 1) > k:
                if max_dq[0] == l:
                    max_dq.popleft()
                if min_dq[0] == l:
                    min_dq.popleft()
                l += 1
            total += r - l + 1
        return total

