var countSubarrays = function(nums, k) {
    const n = nums.length;
    const maxDq = []; // indices, values strictly decreasing front-to-back
    const minDq = []; // indices, values strictly increasing front-to-back
    let maxHead = 0, minHead = 0;
    let l = 0;
    let total = 0;
    for (let r = 0; r < n; r++) {
        while (maxDq.length > maxHead && nums[maxDq[maxDq.length - 1]] <= nums[r]) maxDq.pop();
        maxDq.push(r);
        while (minDq.length > minHead && nums[minDq[minDq.length - 1]] >= nums[r]) minDq.pop();
        minDq.push(r);
        while ((nums[maxDq[maxHead]] - nums[minDq[minHead]]) * (r - l + 1) > k) {
            if (maxDq[maxHead] === l) maxHead++;
            if (minDq[minHead] === l) minHead++;
            l++;
        }
        total += r - l + 1;
    }
    return total;
};
